    if asks_last_order:
        if latest_delivery:
            item_part = f" 품목은 {latest_delivery['items']}입니다." if latest_delivery.get('items') else ''
            amount_part = f" 금액은 {latest_delivery['amountLabel']}입니다." if latest_delivery.get('amount') else ''
