def _ai_workspace_normalize_department_question_answer(data, fallback, context=None):
    if not isinstance(data, dict):
        fallback.setdefault('actionItems', [])
        return _ai_workspace_apply_product_fact_guard(fallback, context or {})
    answer_text = (
        data.get('answer')
        or data.get('summary')
        or data.get('directAnswer')
        or ''
    )
    answer = _ai_workspace_question_answer_text(answer_text, 4200)
    bullets = [
        _ai_workspace_question_text(item, 700)
        for item in _ai_json_list(data.get('bullets') or data.get('keyPoints'))[:10]
        if _ai_workspace_question_text(item, 700)
    ]
    evidence_items = data.get('evidence') or data.get('sourceNotes') or data.get('sources')
    evidence = _ai_workspace_question_evidence_payload(evidence_items, limit=10, value_limit=700)
    decision = _ai_workspace_question_decision_payload(data)
    perspective = _ai_workspace_question_perspective_payload(data)

    action_items = []
    raw_action_items = data.get('actionItems') or data.get('actions') or data.get('recommendedActions')
    for index, item in enumerate(_ai_json_list(raw_action_items)[:5], start=1):
        if not isinstance(item, dict):
            continue
        rank = _ai_workspace_question_int(item.get('rank') or item.get('order'), index)
        crm_evidence = _ai_workspace_question_evidence_payload(
            item.get('crmEvidence') or item.get('evidence') or item.get('sourceNotes') or item.get('sources'),
            limit=4,
            value_limit=520,
        )
        title = _ai_workspace_question_text(item.get('title') or item.get('name') or item.get('action'), 220)
        next_action = _ai_workspace_question_text(
            item.get('nextAction') or item.get('recommendedAction') or item.get('action'),
            900,
        )
        reason = _ai_workspace_question_text(item.get('reason') or item.get('why') or item.get('rationale'), 900)
        timing = _ai_workspace_question_text(
            item.get('timing') or item.get('checkTiming') or item.get('dueDate') or item.get('date'),
            520,
        )
        if not any([title, next_action, reason, timing]):
            continue
        action_items.append({
            'rank': rank,
            'title': title or next_action or f'추천 작업 {rank}',
            'customer': _ai_workspace_question_text(item.get('customer'), 140),
            'company': _ai_workspace_question_text(item.get('company'), 140),
            'department': _ai_workspace_question_text(item.get('department'), 140),
            'priority': _ai_workspace_question_text(item.get('priority') or item.get('priorityLabel'), 90),
            'reason': reason,
            'nextAction': next_action,
            'timing': timing,
            'crmEvidence': crm_evidence,
        })

    confidence = str(data.get('confidence') or fallback.get('confidence') or 'low').strip().lower()
    if confidence not in {'high', 'medium', 'low'}:
        confidence = fallback.get('confidence') or 'low'

    if not answer:
        fallback.setdefault('actionItems', [])
        return _ai_workspace_apply_product_fact_guard(fallback, context or {})
    result = {
        'summary': answer,
        'bullets': bullets,
        'evidence': evidence,
        'actionItems': action_items,
        'confidence': confidence,
    }
    if decision:
        result['decision'] = decision
    if perspective:
        result['perspective'] = perspective
    return _ai_workspace_apply_product_fact_guard(result, context or {})


def _ai_workspace_question_needs_web_search(question):
    normalized = re.sub(r'\s+', '', str(question or '').lower())
    if not normalized:
        return False
    explicit_search = ['웹검색', '인터넷검색', '검색해', '찾아봐', '최신정보', '최신논문', '최신뉴스']
    external_topics = ['논문', '뉴스', '규정', '정책', '시장', '가격', '환율', '트렌드', '업데이트', '출시', 'pubmed', 'fda']
    if any(keyword in normalized for keyword in explicit_search):
        return True
    return '최신' in normalized and any(keyword in normalized for keyword in external_topics)


def _ai_workspace_question_response_guidance(question):
    text = str(question or '').strip()
    compact = re.sub(r'\s+', '', text.lower())
    if not compact:
        return {
            'intent': 'general_crm_answer',
            'instruction': '질문 의도에 맞는 자연스러운 답변 형식을 선택한다.',
        }

    if _ai_workspace_question_is_delivery_payment_split(question):
        return {
            'intent': 'delivery_payment_split',
            'instruction': (
                '선결제/일반결제/선결제 없이 납품 분리 질문이다. '
                'crmContext.deliveryPaymentSplit의 prepaymentDeliveries와 withoutPrepaymentDeliveries만 기준으로 답한다. '
                '메모에 선결제 표현이 있어도 PrepaymentUsage 또는 Schedule 선결제 필드가 없으면 선결제 납품으로 분류하지 않는다. '
                '별도 결제수단 필드가 없으므로 일반결제 확정이라고 쓰지 말고 "선결제 사용 기록 없음"으로 표현한다.'
            ),
        }

    wants_prompt = (
        any(keyword in compact for keyword in ['프롬프트', 'prompt'])
        and any(keyword in compact for keyword in ['만들', '작성', '보낼', '복붙', '그대로', '상담'])
    )
    if wants_prompt:
        return {
            'intent': 'external_ai_prompt',
            'instruction': (
                '외부 AI에게 보낼 완성형 프롬프트 자체를 answer에 바로 제공한다. '
                '추천 판단/버릴 선택/예외 조건/고객별 actionItems 같은 CRM 전략 카드로 풀지 않는다. '
                '필요하면 앞에 한 문장 설명만 붙이고, 대부분은 사용자가 그대로 복사할 수 있는 프롬프트 본문에 집중한다.'
            ),
        }

    wants_email_or_script = (
        any(keyword in compact for keyword in ['메일', '이메일', '회신', '답장', '문자', '카톡', '말문', '스크립트'])
        and any(keyword in compact for keyword in ['써', '작성', '초안', '문안', '보낼', '다듬'])
    )
    if wants_email_or_script:
        return {
            'intent': 'draft_message',
            'instruction': (
                '고객에게 보낼 문안/메일/스크립트 자체를 answer에 완성형으로 쓴다. '
                '분석 카드보다 바로 보낼 수 있는 문장, 제목, 본문 구조를 우선한다.'
            ),
        }

    wants_artifact = any(
        keyword in compact
        for keyword in ['정리본', '1페이지', '한페이지', '체크리스트', '요약본', '비교표', '자료']
    )
    if wants_artifact:
        return {
            'intent': 'business_artifact',
            'instruction': (
                '사용자가 요청한 정리본/비교표/체크리스트 형식으로 바로 쓸 수 있게 작성한다. '
                '필요한 경우에만 간단한 판단 근거를 붙인다.'
            ),
        }

    return {
        'intent': 'strategy_answer',
        'instruction': (
            '질문 성격에 맞춰 자유롭게 답변한다. 선택 판단이나 우선순위 질문이면 구조화해도 되지만, '
            '불필요한 고정 항목을 채우지 않는다.'
        ),
    }


def _ai_workspace_response_output_text(response):
    output_text = getattr(response, 'output_text', None)
    if output_text:
        return output_text
    parts = []
    for item in getattr(response, 'output', []) or []:
        for content in getattr(item, 'content', []) or []:
            text = getattr(content, 'text', None)
            if text:
                parts.append(text)
    return '\n'.join(parts).strip()


def _ai_workspace_json_from_text(text):
    text = str(text or '').strip()
    if not text:
        return {}
    try:
        return json.loads(text)
    except json.JSONDecodeError:
        match = re.search(r'\{.*\}', text, flags=re.S)
        if match:
            return json.loads(match.group(0))
        raise


def _ai_workspace_generate_department_question_answer(
    question,
    context,
    model=None,
    *,
    allow_web_search=True,
    prompt_cache_key='sales-note:ai-workspace-question:v1',
):
    fallback = _ai_workspace_question_fallback(question, context)
    use_web_search = bool(allow_web_search and _ai_workspace_question_needs_web_search(question))
    try:
        from ai_chat.services import (
            create_openai_chat_completion,
            get_openai_client,
            get_standard_openai_model,
            log_openai_usage,
            openai_prompt_cache_kwargs,
        )

        client = get_openai_client()
        model = model or os.environ.get('OPENAI_MODEL_AI_WORKSPACE') or get_standard_openai_model() or AI_WORKSPACE_DEFAULT_QUESTION_MODEL
        response_guidance = _ai_workspace_question_response_guidance(question)
        prompt_payload = {
            'question': question,
            'crmContext': context,
            'webSearchAllowed': use_web_search,
            'responseGuidance': response_guidance,
            'rules': [
                '제공된 crmContext에 있는 사실만 사용한다.',
                'crmContext.recentFeedbacks는 사용자가 AI 추천 실행 목록에 남긴 최신 현장 답변이다. 같은 주제에서는 recentFeedbacks가 older recentSchedules/recentNotes보다 우선한다.',
                'crmContext.recentEmails는 CRM에 연결된 최근 메일 이력이다. 메일/이메일/회신/답장을 참고하라는 질문에서는 recentEmails의 subject, body, directionLabel, date를 우선 근거로 사용한다.',
                'recentEmails가 있는데 "메일 기록을 볼 수 없다"고 답하지 않는다. recentEmails가 비어 있을 때만 연결된 메일 기록이 없다고 말한다.',
                '메일은 보낸 메일과 받은 메일을 구분하고, 본문에 없는 구매 의도/확정 일정/회신 여부를 추측하지 않는다.',
                'crmContext.verifiedMemories는 사용자가 검수해서 저장한 장기 기억이다. 같은 주제에서는 원본 AI 답변 기록보다 verifiedMemories를 우선 적용한다.',
                'verifiedMemories가 CRM 원자료나 제품 마스터와 충돌하면 충돌을 숨기지 말고 어느 근거가 최신/검수 근거인지 분리해서 설명한다.',
                'crmContext.actionFilter는 질문의 제외 조건, 검수 기억상 해결된 고객, 최근 보낸 메일로 이미 접촉한 고객을 반영해 실행 후보를 걸러낸 결과다.',
                'crmContext.actionFilter.skippedActions에 있는 고객은 오늘 할 일 또는 actionItems로 추천하지 않는다. 필요하면 "이미 처리/제외/최근 메일 발송으로 뺐다" 정도로만 언급한다.',
                'crmContext.actionFilter.recentOutboundContacts는 최근 2일 안에 사용자가 이미 보낸 메일이다. 오늘 할 일 질문에서는 이 고객을 새 연락 후보로 다시 올리지 않는다.',
                'crmContext.recentQuestionLogs는 현재 대화 흐름을 이어가기 위한 약한 문맥이다. recentQuestionLogs의 과거 AI 답변은 사실 근거가 아니며 CRM 원자료, 메일, 제품 마스터, verifiedMemories보다 우선하지 않는다.',
                'crmContext.questionFeedbacks는 현재 사용자가 이전 AI 질문 답변에 남긴 평가다. CRM 사실이 아니라 답변 방식 선호와 반복 오류 회피 기준으로만 사용한다.',
                'questionFeedbacks에 needs_style 또는 incorrect 코멘트가 있으면 같은 표현 방식이나 판단 오류를 반복하지 않는다.',
                'crmContext.productFacts는 제품 코드별 제품 마스터 설명/규격/단위다. 제품 코드의 품목 성격은 productFacts와 CRM 품목 메모를 우선 근거로 삼는다.',
                '제품 코드는 식별자다. productFacts.label/description/specification 또는 CRM 메모에 없는 품목 유형을 코드 앞에 새로 붙이지 않는다.',
                '예를 들어 productFacts에 튜브 근거가 없으면 "튜브(P4345N00)"처럼 쓰지 말고 productFacts.label 또는 "P4345N00 품목"처럼 쓴다.',
                'crmContext.deliveryPaymentSplit은 납품별 선결제 사용 여부를 구조화 데이터로 분리한 표다. 선결제 납품은 Schedule.use_prepayment, Schedule.prepayment, Schedule.prepayment_amount, PrepaymentUsage 중 하나가 확인될 때만 prepaymentDeliveries에 들어간다.',
                '선결제/일반결제/그냥 결제/선결제 없이 납품 구분 질문에서는 crmContext.deliveryPaymentSplit을 우선 근거로 사용하고, recentNotes/recentEmails/recentQuestionLogs/납품 notes의 선결제 언급만으로 분류하지 않는다.',
                'withoutPrepaymentDeliveries는 별도 결제수단 확정이 아니라 구조화 선결제 사용 기록이 없는 납품이다. CRM에 일반결제 필드가 없으면 "일반결제 확정"이 아니라 "선결제 사용 기록 없음"이라고 표현한다.',
                '이전 일정에는 "해야 함"이라고 적혀 있고 최신 feedback/노트에는 "했다/줬다/완료"라고 적혀 있으면 완료된 것으로 해석하고 둘을 같은 미완료 액션처럼 반복하지 않는다.',
                '질문이 마지막 주문/납품/구매일을 묻는 경우 crmContext.lastDelivery.date를 우선 사용한다.',
                '질문이 실행할 작업/다음 액션을 묻는다면 범위가 전체 부서든 선택 부서든 crmContext.recommendedActions와 openFollowups를 우선 보고 후보를 골라준다.',
                '주문이라는 표현은 이 CRM에서는 납품/수주 기록과 연결해 해석하되, 근거 출처를 명시한다.',
                'webSearchAllowed가 true이고 최신 외부 정보가 필요한 질문에서만 웹 검색 결과를 보조 근거로 사용한다. 내부 CRM 고객명/영업내용을 웹 검색어로 노출하지 않는다.',
                '데이터가 없으면 없다고 답하고 추측하지 않는다.',
                '단, CRM 근거가 있는 고객 심리/구매 의도 해석은 answer 또는 perspective에 "고객 입장에서는", "가능성이 있습니다"처럼 추정임을 표시해 쓴다.',
                '고객 마음을 단정하지 말고, CRM 사실과 추정을 분리한다.',
                'responseGuidance.intent와 responseGuidance.instruction을 우선 적용한다.',
                '질문이 프롬프트/메일/문안/정리본 생성을 요구하면 answer에 그 산출물 자체를 완성형으로 쓴다.',
                '프롬프트 생성 요청에서는 추천 판단, 버릴 선택, 예외 조건, 고객별 actionItems를 만들지 않는다.',
                '답변 형식은 질문 의도에 맞게 자유롭게 선택한다. 모든 답변에 같은 제목이나 카드 구조를 반복하지 않는다.',
                'answer가 4문장 이상이거나 번호/비교/품목 목록을 포함하면 문단 사이에 줄바꿈을 넣는다. 1), 2), 3) 같은 번호 항목과 - 항목은 각각 새 줄에서 시작한다.',
                '질문이 "할까/말까", "A가 좋을까 B가 좋을까", "아니면", "굳이"처럼 선택지형이면 answer 첫 문장에 추천 선택을 먼저 말한다.',
                'decision은 선택지가 분명하고 별도 판단 카드가 유용할 때만 넣는다. 단순 산출물 작성 요청에는 decision을 비운다.',
                'perspective는 고객 심리 추정이나 영업 관점 분리가 실제로 도움이 될 때만 넣는다. 단순 산출물 작성 요청에는 perspective를 비운다.',
                '실행해야 할 작업 목록 자체가 질문의 목적이면 actionItems에 최대 5개를 우선순위 순서로 넣는다.',
                '단순 설명, 프롬프트 작성, 메일 초안, 문안 작성 요청에는 actionItems를 비우거나 생략한다.',
                '각 actionItems 항목은 title, customer, company, department, priority, reason, nextAction, timing, crmEvidence를 채운다.',
                'reason, nextAction, timing은 짧은 단어 조각이 아니라 실행자가 바로 이해할 수 있는 한 문장 이상으로 쓴다.',
                'bullets는 보조 요약만 넣고, 고객별 실행 상세는 actionItems에 넣는다.',
                '이 애플리케이션은 JSON 객체만 파싱한다. JSON 바깥의 Markdown 본문은 쓰지 않는다.',
                '반드시 JSON 객체만 반환한다. 기본 형태는 {"answer": string, "bullets": string[], "evidence": [{"label": string, "value": string}], "confidence": "high|medium|low"} 이다.',
                '필요할 때만 선택적으로 "decision", "perspective", "actionItems"를 추가한다.',
            ],
        }
        system_prompt = AI_WORKSPACE_CRM_STRATEGY_SYSTEM_PROMPT
        data = None
        if use_web_search and hasattr(client, 'responses'):
            response_kwargs = {
                'model': model,
                'input': [
                    {'role': 'system', 'content': system_prompt},
                    {'role': 'user', 'content': json.dumps(prompt_payload, ensure_ascii=False, cls=DjangoJSONEncoder)},
                ],
                'tools': [{'type': 'web_search'}],
                'tool_choice': 'auto',
                'include': ['web_search_call.action.sources'],
                'max_output_tokens': AI_WORKSPACE_DEPARTMENT_QUESTION_OUTPUT_TOKENS,
                **openai_prompt_cache_kwargs(prompt_cache_key),
            }
            try:
                response = client.responses.create(**response_kwargs)
            except TypeError as exc:
                if prompt_cache_key and 'prompt_cache' in str(exc):
                    response_kwargs.pop('prompt_cache_key', None)
                    response_kwargs.pop('prompt_cache_retention', None)
                    response = client.responses.create(**response_kwargs)
                else:
                    raise
            log_openai_usage('ai_workspace_question', model, response)
            data = _ai_workspace_json_from_text(_ai_workspace_response_output_text(response))
            web_search_used = any(
                (item.get('type') if isinstance(item, dict) else getattr(item, 'type', '')) == 'web_search_call'
                for item in getattr(response, 'output', []) or []
            )
        else:
            response = create_openai_chat_completion(
                client,
                'ai_workspace_question',
                model,
                [
                    {
                        'role': 'system',
                        'content': system_prompt,
                    },
                    {
                        'role': 'user',
                        'content': json.dumps(prompt_payload, ensure_ascii=False, cls=DjangoJSONEncoder),
                    },
                ],
                response_format={'type': 'json_object'},
                temperature=0.2,
                max_tokens=AI_WORKSPACE_DEPARTMENT_QUESTION_OUTPUT_TOKENS,
                prompt_cache_key=prompt_cache_key,
            )
            data = _ai_workspace_json_from_text(response.choices[0].message.content)
            web_search_used = False
        answer = _ai_workspace_normalize_department_question_answer(data, fallback, context)
        return answer, 'openai', web_search_used
    except Exception as exc:
        logger.warning('AI workspace department question fallback used: %s', exc)
        fallback.setdefault('actionItems', [])
        return _ai_workspace_apply_product_fact_guard(fallback, context), 'fallback', False


def _customer_ai_primary_context(followup):
    return {
        'id': followup.id,
        'name': followup.customer_name or followup.manager or '고객명 미정',
        'manager': followup.manager or '',
        'company': followup.company.name if followup.company else '',
        'department': followup.department.name if followup.department else '',
        'priority': followup.get_priority_display(),
        'status': followup.get_status_display(),
        'grade': followup.customer_grade or '',
        'score': followup.ai_score or 0,
        'pipelineStage': followup.get_pipeline_stage_display(),
        'email': followup.email or '',
        'phone': followup.phone_number or '',
        'notes': _ai_workspace_question_text(followup.notes, 700),
    }


SCHEDULE_AI_COACH_OUTPUT_TOKENS = 1400


def _schedule_ai_report_action_type(activity_type):
    if activity_type in {'customer_meeting', 'quote', 'delivery_schedule', 'service'}:
        return activity_type
    return {
        'quote': 'quote',
        'delivery': 'delivery_schedule',
        'service': 'service',
        'customer_meeting': 'customer_meeting',
    }.get(activity_type, 'customer_meeting')


def _schedule_ai_coach_context(schedule, actor):
    followup = schedule.followup
    department = followup.department if followup and followup.department_id else None
    email_thread_count = EmailLog.objects.filter(
        schedule=schedule,
        gmail_thread_id__isnull=False,
    ).exclude(gmail_thread_id='').values('gmail_thread_id').distinct().count()
    delivery_text, delivery_total = _schedules_delivery_items_summary(schedule)
    documents = _schedules_document_actions(schedule, actor)
    commercial_checks = _schedules_commercial_checks(
        schedule,
        actor,
        documents,
        email_thread_count,
    )

    related_notes = []
    related_note_qs = History.objects.filter(
        Q(schedule=schedule) | Q(followup=followup),
        user=schedule.user,
        parent_history__isnull=True,
    ).exclude(action_type='memo').select_related('followup').distinct().order_by('-created_at')[:10]
    for history in related_note_qs:
        activity_date = history.meeting_date or history.delivery_date
        date_label = activity_date.isoformat() if activity_date else timezone.localtime(history.created_at).date().isoformat()
        related_notes.append({
            'date': date_label,
            'type': history.get_action_type_display(),
            'content': _ai_workspace_question_text(_history_activity_content(history), 760),
            'nextAction': _ai_workspace_question_text(history.next_action or history.meeting_next_action, 320),
            'nextActionDate': _date_or_none(history.next_action_date),
        })

    return {
        'scope': {
            'type': 'schedule',
            'label': ' · '.join(_ai_prompt_context(
                followup.company.name if followup and followup.company else '',
                followup.department.name if followup and followup.department else '',
                followup.customer_name if followup else '',
                schedule.get_activity_type_display(),
            )),
            'scheduleId': schedule.id,
            'followupId': followup.id if followup else None,
            'departmentId': department.id if department else None,
        },
        'schedule': {
            'id': schedule.id,
            'date': _date_or_none(schedule.visit_date),
            'time': schedule.visit_time.strftime('%H:%M') if schedule.visit_time else '',
            'activityType': schedule.activity_type,
            'activityLabel': schedule.get_activity_type_display(),
            'status': schedule.status,
            'statusLabel': schedule.get_status_display(),
            'location': schedule.location or '',
            'notes': _ai_workspace_question_text(schedule.notes, 900),
            'expectedRevenue': _money_int(schedule.expected_revenue),
            'probability': schedule.probability or 0,
            'expectedCloseDate': _date_or_none(schedule.expected_close_date),
            'purchaseConfirmed': bool(schedule.purchase_confirmed),
            'vatMode': schedule.vat_mode,
            'usePrepayment': bool(schedule.use_prepayment),
            'prepaymentAmount': _money_int(schedule.prepayment_amount),
        },
        'customer': _customer_ai_primary_context(followup) if followup else {},
        'deliverySummary': {
            'itemsText': _ai_workspace_question_text(delivery_text, 900),
            'totalAmount': delivery_total,
        },
        'deliveryItems': [
            _schedules_delivery_item_payload(item)
            for item in schedule.delivery_items_set.all().order_by('id')[:12]
        ],
        'commercialChecks': {
            'status': commercial_checks.get('status'),
            'statusLabel': commercial_checks.get('statusLabel'),
            'summary': commercial_checks.get('summary'),
            'warnings': commercial_checks.get('warnings') or [],
        },
        'recentNotes': related_notes,
        'recentEmails': _ai_workspace_recent_email_context(
            schedule.user,
            followup_ids=[followup.id] if followup else [],
            department_id=department.id if department else None,
            limit=8,
        ),
        'recentFeedbacks': _ai_workspace_question_recent_feedbacks(schedule.user, [followup.id] if followup else [], limit=6),
        'verifiedMemories': _ai_workspace_verified_memories(
            actor,
            department_id=department.id if department else None,
            scope_type='department' if department else 'all',
        ),
    }


def _schedule_ai_evidence_from_context(context):
    schedule = context.get('schedule') or {}
    customer = context.get('customer') or {}
    delivery_summary = context.get('deliverySummary') or {}
    evidence = [
        {
            'label': '일정',
            'value': ' · '.join(_ai_prompt_context(
                schedule.get('date'),
                schedule.get('time'),
                schedule.get('activityLabel'),
                schedule.get('statusLabel'),
            )),
        },
        {
            'label': '고객',
            'value': ' · '.join(_ai_prompt_context(
                customer.get('company'),
                customer.get('department'),
                customer.get('name'),
                customer.get('pipelineStage'),
            )),
        },
    ]
    if delivery_summary.get('itemsText'):
        evidence.append({
            'label': '품목',
            'value': delivery_summary.get('itemsText'),
        })
    return _ai_workspace_question_evidence_payload(evidence, limit=5, value_limit=700)


def _schedule_ai_coach_fallback(context):
    schedule = context.get('schedule') or {}
    customer = context.get('customer') or {}
    activity_type = schedule.get('activityType') or ''
    activity_label = schedule.get('activityLabel') or '일정'
    customer_label = customer.get('name') or '고객'
    amount = _money_int(schedule.get('expectedRevenue') or (context.get('deliverySummary') or {}).get('totalAmount') or 0)
    date_label = ' '.join(_ai_prompt_context(schedule.get('date'), schedule.get('time'))) or '일정 시간'
    delivery_items = context.get('deliveryItems') or []

    if activity_type == 'quote':
        summary = f"{customer_label} 견적 일정입니다. 견적 금액, 품목, 의사결정 일정, 다음 회신 기한을 이 일정에서 확정하는 쪽으로 움직이세요."
        talk_track = [
            '이번 견적 기준에서 수량, 납기, 예산 중 어느 조건이 먼저 맞아야 진행 가능한지 확인합니다.',
            '견적서를 보낸 뒤 언제까지 내부 확인이 가능한지 날짜로 받습니다.',
            '가격을 먼저 낮추기보다 변경 가능한 조건과 필수 조건을 분리해 묻습니다.',
        ]
        checklist = ['견적 품목/수량 재확인', '의사결정자와 내부 결재 일정 확인', '견적 유효기간과 다음 회신일 설정']
        recommended_next_action = '견적 전달 후 회신 기한을 CRM 후속일로 잡고, 필요한 수정 조건을 한 번에 정리합니다.'
    elif activity_type == 'delivery':
        summary = f"{customer_label} 납품 일정입니다. 품목, 수량, 세금계산서, 선결제 차감 여부를 현장에서 누락 없이 확인해야 합니다."
        talk_track = [
            '납품 품목과 수량이 맞는지 먼저 같이 확인합니다.',
            '세금계산서 발행 기준과 선결제 차감 여부를 고객에게 명확히 확인합니다.',
            '추가 소모품이나 다음 발주 예상 시점을 짧게 물어 다음 기회를 만듭니다.',
        ]
        checklist = ['납품 품목/수량 확인', '세금계산서와 결제 방식 확인', '다음 사용 예정일과 재주문 가능성 확인']
        recommended_next_action = '납품 완료 여부와 세금계산서/결제 상태를 노트에 남기고 다음 재구매 확인일을 잡습니다.'
    elif activity_type == 'service':
        summary = f"{customer_label} 서비스 일정입니다. 증상, 사용 조건, 긴급도, 후속 처리 기준을 분리해 기록하는 것이 핵심입니다."
        talk_track = [
            '현재 증상이 언제부터 어떤 조건에서 반복되는지 확인합니다.',
            '사용 제품, 로트, 사진/동영상 근거가 있는지 확인합니다.',
            '교체, 회수, 추가 확인 중 어떤 처리 방향을 기대하는지 묻습니다.',
        ]
        checklist = ['증상과 발생 조건 확인', '제품/로트/사진 근거 확보', '처리 예정일과 담당자 합의']
        recommended_next_action = '서비스 증상과 처리 예정일을 노트에 남기고 고객에게 다음 안내 시점을 공유합니다.'
    else:
        summary = f"{customer_label} 고객 미팅 일정입니다. 이 일정에서는 고객의 현재 실험/구매 맥락과 다음 제안 조건을 확인하는 데 집중하세요."
        talk_track = [
            '최근 사용 중인 품목과 불편한 점을 먼저 확인합니다.',
            '다음 실험 일정, 예산, 구매 가능 시점을 짧게 물어봅니다.',
            '바로 팔기보다 다음 견적이나 샘플 제안으로 이어질 조건을 찾습니다.',
        ]
        checklist = ['현재 사용 품목 확인', '다음 실험/구매 일정 확인', '견적/샘플 필요 여부 확인']
        recommended_next_action = '미팅에서 확인한 구매 조건과 다음 연락일을 CRM 후속 액션으로 남깁니다.'

    risks = []
    if activity_type in {'quote', 'delivery'} and not delivery_items and not (context.get('deliverySummary') or {}).get('itemsText'):
        risks.append({'level': 'medium', 'label': '품목 누락', 'value': '견적/납품 품목이 비어 있어 현장 확인이나 서류 자동화가 흔들릴 수 있습니다.'})
    if amount <= 0 and activity_type in {'quote', 'delivery'}:
        risks.append({'level': 'low', 'label': '금액 미입력', 'value': '예상 금액이 없어 매출 영향과 우선순위 판단이 약합니다.'})
    if not (context.get('recentEmails') or []):
        risks.append({'level': 'low', 'label': '메일 근거 부족', 'value': '최근 연결 메일이 없어 고객의 최신 문면 요청은 확인되지 않았습니다.'})

    note_content = (
        f"[{activity_label}] {date_label} {customer_label} 일정 진행. "
        f"핵심 확인: {' / '.join(checklist[:3])}. "
        f"권장 대응: {recommended_next_action}"
    )
    if schedule.get('notes'):
        note_content += f" 기존 일정 메모: {schedule.get('notes')}"

    return {
        'summary': summary,
        'priority': 'high' if activity_type in {'quote', 'delivery'} else 'medium',
        'talkTrack': talk_track,
        'checklist': checklist,
        'risks': risks,
        'recommendedNextAction': recommended_next_action,
        'afterMeetingNoteDraft': {
            'actionType': _schedule_ai_report_action_type(activity_type),
            'content': _ai_workspace_question_text(note_content, 1600),
            'nextAction': recommended_next_action,
        },
        'mailDraft': {
            'subject': f"{customer_label} {activity_label} 후속 확인",
            'body': (
                f"안녕하세요.\n\n{activity_label} 관련해 오늘 확인한 내용을 기준으로 필요한 조건을 정리해드리겠습니다.\n"
                f"{recommended_next_action}\n\n확인 후 회신드리겠습니다."
            ),
        },
        'evidence': _schedule_ai_evidence_from_context(context),
        'confidence': 'medium' if context.get('recentNotes') or context.get('deliveryItems') else 'low',
    }


def _schedule_ai_text_list(value, limit=6, text_limit=420):
    return [
        _ai_workspace_question_text(item, text_limit)
        for item in _ai_json_list(value)[:limit]
        if _ai_workspace_question_text(item, text_limit)
    ]


def _schedule_ai_risk_payload(value):
    risks = []
    for item in _ai_json_list(value)[:5]:
        if isinstance(item, dict):
            label = _ai_workspace_question_text(item.get('label') or item.get('title') or item.get('risk'), 160)
            risk_value = _ai_workspace_question_text(item.get('value') or item.get('detail') or item.get('reason'), 520)
            level = _ai_workspace_question_text(item.get('level') or item.get('severity'), 40) or 'medium'
        else:
            label = '주의'
            risk_value = _ai_workspace_question_text(item, 520)
            level = 'medium'
        if label or risk_value:
            risks.append({
                'level': level if level in {'high', 'medium', 'low'} else 'medium',
                'label': label or '주의',
                'value': risk_value,
            })
    return risks


def _normalize_schedule_ai_coach(data, fallback):
    if not isinstance(data, dict):
        return fallback

    note_draft = data.get('afterMeetingNoteDraft') or data.get('reportDraft') or {}
    if not isinstance(note_draft, dict):
        note_draft = {}
    fallback_note = fallback.get('afterMeetingNoteDraft') or {}

    mail_draft = data.get('mailDraft') or data.get('emailDraft') or {}
    if not isinstance(mail_draft, dict):
        mail_draft = {}
    fallback_mail = fallback.get('mailDraft') or {}

    confidence = _ai_workspace_question_text(data.get('confidence') or fallback.get('confidence'), 20).lower()
    if confidence not in {'high', 'medium', 'low'}:
        confidence = fallback.get('confidence') or 'low'

    result = {
        'summary': _ai_workspace_question_text(data.get('summary') or data.get('answer'), 1400) or fallback.get('summary', ''),
        'priority': _ai_workspace_question_text(data.get('priority'), 40) or fallback.get('priority', 'medium'),
        'talkTrack': _schedule_ai_text_list(data.get('talkTrack') or data.get('talk_track'), limit=5) or fallback.get('talkTrack', []),
        'checklist': _schedule_ai_text_list(data.get('checklist') or data.get('checks'), limit=7) or fallback.get('checklist', []),
        'risks': _schedule_ai_risk_payload(data.get('risks')) or fallback.get('risks', []),
        'recommendedNextAction': _ai_workspace_question_text(
            data.get('recommendedNextAction') or data.get('nextAction'),
            760,
        ) or fallback.get('recommendedNextAction', ''),
        'afterMeetingNoteDraft': {
            'actionType': _schedule_ai_report_action_type(
                note_draft.get('actionType') or fallback_note.get('actionType') or 'customer_meeting'
            ),
            'content': _ai_workspace_question_text(note_draft.get('content'), 1800) or fallback_note.get('content', ''),
            'nextAction': _ai_workspace_question_text(
                note_draft.get('nextAction') or note_draft.get('next_action'),
                760,
            ) or fallback_note.get('nextAction', ''),
        },
        'mailDraft': {
            'subject': _ai_workspace_question_text(mail_draft.get('subject'), 220) or fallback_mail.get('subject', ''),
            'body': _ai_workspace_question_text(mail_draft.get('body') or mail_draft.get('content'), 1800) or fallback_mail.get('body', ''),
        },
        'evidence': _ai_workspace_question_evidence_payload(data.get('evidence'), limit=6, value_limit=700) or fallback.get('evidence', []),
        'confidence': confidence,
    }
    return result


def _generate_schedule_ai_coach(context, model=None):
    fallback = _schedule_ai_coach_fallback(context)
    selected_model = model or AI_WORKSPACE_DEFAULT_QUESTION_MODEL
    try:
        from ai_chat.services import create_openai_chat_completion, get_openai_client, get_standard_openai_model

        selected_model = (
            model
            or os.environ.get('OPENAI_MODEL_SCHEDULE_COACH')
            or os.environ.get('OPENAI_MODEL_AI_WORKSPACE')
            or get_standard_openai_model()
            or AI_WORKSPACE_DEFAULT_QUESTION_MODEL
        )
        client = get_openai_client()
        prompt_payload = {
            'crmContext': context,
            'rules': [
                '제공된 crmContext에 있는 CRM 사실만 사용한다.',
                '일정 상세 화면에서 바로 행동할 수 있는 실행 추천을 만든다.',
                '질문을 기다리는 Q&A가 아니라 이 일정에서 어떻게 말하고 확인하고 기록할지 추천한다.',
                '일정 유형이 견적이면 견적 조건, 회신 기한, 의사결정 일정을 우선한다.',
                '일정 유형이 납품이면 품목, 수량, 세금계산서, 선결제, 다음 재주문 가능성을 우선한다.',
                '일정 유형이 서비스이면 증상, 근거 확보, 처리 예정일을 우선한다.',
                'afterMeetingNoteDraft는 저장하지 않을 초안이므로 사실과 확인 필요를 분리해 쓴다.',
                '없는 구매 의사, 납품 완료, 고객 마음을 만들어내지 않는다.',
                '웹 검색은 사용하지 않는다.',
                'JSON 객체만 반환한다.',
            ],
            'outputSchema': {
                'summary': 'string',
                'priority': 'high|medium|low',
                'talkTrack': ['string'],
                'checklist': ['string'],
                'risks': [{'level': 'high|medium|low', 'label': 'string', 'value': 'string'}],
                'recommendedNextAction': 'string',
                'afterMeetingNoteDraft': {
                    'actionType': 'customer_meeting|quote|delivery_schedule|service',
                    'content': 'string',
                    'nextAction': 'string',
                },
                'mailDraft': {'subject': 'string', 'body': 'string'},
                'evidence': [{'label': 'string', 'value': 'string'}],
                'confidence': 'high|medium|low',
            },
        }
        response = create_openai_chat_completion(
            client,
            'schedule_ai_coach',
            selected_model,
            [
                {
                    'role': 'system',
                    'content': (
                        '너는 B2B 영업 CRM의 일정 실행 코치다. '
                        '현재 일정과 연결 고객 기록만 보고, 담당자가 이 일정에서 어떻게 행동해야 하는지 한국어로 구체적으로 추천한다. '
                        '반드시 JSON 객체만 반환한다.'
                    ),
                },
                {
                    'role': 'user',
                    'content': json.dumps(prompt_payload, ensure_ascii=False, cls=DjangoJSONEncoder),
                },
            ],
            response_format={'type': 'json_object'},
            temperature=0.2,
            max_tokens=SCHEDULE_AI_COACH_OUTPUT_TOKENS,
            prompt_cache_key='sales-note:schedule-coach:v1',
        )
        data = _ai_workspace_json_from_text(response.choices[0].message.content)
        return _normalize_schedule_ai_coach(data, fallback), 'openai', selected_model
    except Exception as exc:
        logger.warning('Schedule AI coach fallback used: %s', exc)
        return fallback, 'fallback', selected_model


@never_cache
@require_POST
def schedule_ai_coach_api(request, schedule_id):
    """Generate unsaved execution coaching for one schedule detail screen."""
    auth_response = _api_login_required_response(request)
    if auth_response:
        return auth_response

    user_profile = get_user_profile(request.user)
    if not (user_profile and user_profile.can_use_ai):
        return JsonResponse({
            'success': False,
            'error': 'permission_denied',
            'message': 'AI 기능 사용 권한이 없습니다.',
        }, status=403)

    schedule = _schedules_get_detail_schedule(schedule_id)
    if not can_access_user_data(request.user, schedule.user):
        return JsonResponse({
            'success': False,
            'error': 'permission_denied',
            'message': '접근 권한이 없습니다.',
        }, status=403)

    context = _schedule_ai_coach_context(schedule, request.user)
    coach, source, selected_model = _generate_schedule_ai_coach(context)
    return JsonResponse({
        'success': True,
        'source': source,
        'model': selected_model,
        'modelLabel': _ai_workspace_question_model_label(selected_model),
        'generatedAt': timezone.now().isoformat(),
        'scope': context.get('scope') or {},
        'coach': coach,
        'context': {
            'scheduleId': schedule.id,
            'followupId': schedule.followup_id,
            'departmentId': schedule.followup.department_id if schedule.followup else None,
            'recentNoteCount': len(context.get('recentNotes') or []),
            'recentEmailCount': len(context.get('recentEmails') or []),
            'deliveryItemCount': len(context.get('deliveryItems') or []),
            'stored': False,
        },
        'requiresHumanReview': True,
    })


@never_cache
@require_http_methods(["GET"])
def ai_workspace_summary_api(request):
    """React CRM AI workspace 화면용 읽기 전용 API."""
    from datetime import timedelta
    from ai_chat.department_prompt import suggest_goals_from_department_analysis
    from ai_chat.models import AIDepartmentAnalysis, AIFollowUpAnalysis, PainPointCard

    auth_response = _api_login_required_response(request)
    if auth_response:
        return auth_response

    user_profile = get_user_profile(request.user)
    can_use_ai = bool(user_profile and user_profile.can_use_ai)
    today = timezone.localdate()
    week_start = today - timedelta(days=today.weekday())
    week_end = week_start + timedelta(days=4)

    base_links = {
        'aiHub': '/ai-workspace/',
        'weeklyReports': '/weekly-reports/',
        'weeklyReportCreate': '/weekly-reports/new/',
        'weeklyAiDraft': (
            f"{reverse('reporting:weekly_report_ai_draft')}"
            f"?week_start={week_start.isoformat()}&week_end={week_end.isoformat()}"
        ),
        'customers': '/customers/',
        'notes': '/notes/',
        'dashboard': '/dashboard/',
    }

    current_user = {
        'id': request.user.id,
        'name': _user_display_name(request.user),
        'role': user_profile.role,
        'roleLabel': user_profile.get_role_display(),
        'company': user_profile.company.name if user_profile.company else '',
        'canUseAi': can_use_ai,
    }

    if not can_use_ai:
        return JsonResponse({
            'success': True,
            'source': 'django',
            'generatedAt': timezone.now().isoformat(),
            'currentUser': current_user,
            'permission': {
                'canUseAi': False,
                'message': 'AI 기능 사용 권한이 없습니다. 관리자에게 문의하세요.',
            },
            'metrics': {
                'departmentsWithCustomers': 0,
                'analyzedDepartments': 0,
                'painpointCards': 0,
                'unverifiedPainpoints': 0,
                'followupAnalyses': 0,
                'weeklyReportsThisMonth': 0,
            },
            'links': base_links,
            'week': {
                'start': week_start.isoformat(),
                'end': week_end.isoformat(),
            },
            'dailyBrief': _ai_workspace_empty_daily_brief(week_start, week_end),
            'actionQueue': [],
            'feedbackHistory': _ai_workspace_empty_feedback_history(),
            'departments': [],
            'recentDepartmentAnalyses': [],
            'painpoints': [],
            'followupTargets': [],
            'recentFollowupAnalyses': [],
            'promptTargets': [],
            'recommendedGoals': [],
            'featuredDepartment': None,
            'selectedDepartmentId': None,
            'questionHistory': _ai_workspace_empty_question_history(),
            'questionModelChoices': _ai_workspace_question_model_choices_payload(),
            'defaultQuestionModel': AI_WORKSPACE_DEFAULT_QUESTION_MODEL,
        })

    followup_rows = list(FollowUp.objects.filter(
        user=request.user,
        department__isnull=False,
    ).values('id', 'department_id', 'customer_name', 'manager').order_by('department_id', 'customer_name'))
    customer_names_by_department = {}
    followup_counts_by_department = {}
    followup_ids_by_department = {}
    search_terms_by_department = {}
    for row in followup_rows:
        department_id = row['department_id']
        followup_counts_by_department[department_id] = followup_counts_by_department.get(department_id, 0) + 1
        followup_ids_by_department.setdefault(department_id, []).append(row['id'])
        if row['customer_name']:
            customer_names_by_department.setdefault(department_id, []).append(row['customer_name'])
        search_terms = search_terms_by_department.setdefault(department_id, [])
        for key in ('customer_name', 'manager'):
            value = (row.get(key) or '').strip()
            if value and value not in search_terms:
                search_terms.append(value)

    department_ids = list(followup_counts_by_department.keys())
    departments = list(Department.objects.filter(
        id__in=department_ids,
    ).select_related('company').order_by('company__name', 'name'))
    analyses = list(AIDepartmentAnalysis.objects.filter(
        user=request.user,
        department_id__in=department_ids,
    ).select_related('department', 'department__company').order_by('-updated_at'))
    analysis_map = {analysis.department_id: analysis for analysis in analyses}
    requested_department_id = None
    requested_department_value = request.GET.get('department_id') or request.GET.get('department')
    if requested_department_value:
        try:
            requested_department_id = int(requested_department_value)
        except (TypeError, ValueError):
            requested_department_id = None
    try:
        question_page = int(request.GET.get('question_page') or request.GET.get('questionPage') or 1)
    except (TypeError, ValueError):
        question_page = 1
    question_page = max(1, question_page)
    question_scope = str(
        request.GET.get('question_scope') or request.GET.get('questionScope') or 'department'
    ).strip().lower()
    if question_scope not in {'all', 'department'}:
        question_scope = 'department'
    selected_department = (
        next((department for department in departments if department.id == requested_department_id), None)
        if requested_department_id
        else None
    )
    detail_department = selected_department if requested_department_id and selected_department else None

    painpoint_counts = {
        item['analysis_id']: item['count']
        for item in PainPointCard.objects.filter(
            analysis__user=request.user,
        ).values('analysis_id').annotate(count=Count('id'))
    }
    unverified_counts = {
        item['analysis_id']: item['count']
        for item in PainPointCard.objects.filter(
            analysis__user=request.user,
            verification_status='unverified',
        ).values('analysis_id').annotate(count=Count('id'))
    }

    department_payload = []
    for department in departments:
        analysis = analysis_map.get(department.id)
        customer_names = customer_names_by_department.get(department.id, [])
        department_payload.append({
            'id': department.id,
            'name': department.name,
            'company': department.company.name if department.company else '',
            'customerCount': followup_counts_by_department.get(department.id, 0),
            'customerPreview': customer_names[:4],
            'searchText': ' '.join(search_terms_by_department.get(department.id, [])),
            'hasAnalysis': analysis is not None,
            'meetingCount': analysis.meeting_count if analysis else 0,
            'quoteCount': analysis.quote_count if analysis else 0,
            'deliveryCount': analysis.delivery_count if analysis else 0,
            'painpointCount': painpoint_counts.get(analysis.id, 0) if analysis else 0,
            'unverifiedPainpointCount': unverified_counts.get(analysis.id, 0) if analysis else 0,
            'summary': _ai_workspace_analysis_summary(analysis) if analysis else '',
            'updatedAt': _datetime_or_none(analysis.updated_at) if analysis else None,
            'href': reverse('ai_chat:department_analysis', args=[department.id]),
            'hubHref': f"{reverse('ai_chat:department_list')}?department={department.id}",
            'runHref': reverse('ai_chat:run_analysis', args=[department.id]),
        })

    painpoint_payload = []
    painpoint_cards_qs = PainPointCard.objects.filter(
        analysis__user=request.user,
        verification_status='unverified',
    )
    if detail_department:
        painpoint_cards_qs = painpoint_cards_qs.filter(analysis__department=detail_department)
    painpoint_cards = list(
        painpoint_cards_qs.select_related('analysis', 'analysis__department', 'analysis__department__company').order_by(
            '-confidence_score', '-created_at'
        )[:8]
    )
    for card in painpoint_cards:
        department = card.analysis.department
        painpoint_payload.append({
            'id': card.id,
            'category': card.category,
            'categoryLabel': card.get_category_display(),
            'hypothesis': card.hypothesis[:180],
            'confidence': card.confidence,
            'confidenceLabel': card.get_confidence_display(),
            'confidenceScore': card.confidence_score,
            'department': department.name,
            'company': department.company.name if department.company else '',
            'question': card.verification_question[:160],
            'href': reverse('ai_chat:department_analysis', args=[department.id]),
        })

    followup_analyses_qs = AIFollowUpAnalysis.objects.filter(
        user=request.user,
    )
    if detail_department:
        followup_analyses_qs = followup_analyses_qs.filter(followup__department=detail_department)
    followup_analyses = list(
        followup_analyses_qs.select_related('followup', 'followup__company', 'followup__department').order_by('-updated_at')[:8]
    )
    followup_analysis_map = {analysis.followup_id: analysis for analysis in followup_analyses}
    followup_targets = []
    followup_targets_qs = FollowUp.objects.filter(
        user=request.user,
    )
    if detail_department:
        followup_targets_qs = followup_targets_qs.filter(department=detail_department)
    for followup in followup_targets_qs.select_related('company', 'department').order_by('-ai_score', '-updated_at')[:10]:
        analysis = followup_analysis_map.get(followup.id)
        followup_targets.append({
            'id': followup.id,
            'customer': followup.customer_name or followup.manager or '고객명 미정',
            'company': followup.company.name if followup.company else '',
            'department': followup.department.name if followup.department else '',
            'grade': followup.customer_grade or '',
            'score': float(followup.get_combined_score()),
            'priority': followup.priority,
            'priorityLabel': followup.get_priority_display(),
            'hasAnalysis': analysis is not None,
            'analysisUpdatedAt': _datetime_or_none(analysis.updated_at) if analysis else None,
            'analysisSummary': _ai_workspace_analysis_summary(analysis) if analysis else '',
            'href': reverse('ai_chat:followup_analysis', args=[followup.id]),
            'customerHref': reverse('reporting:followup_detail', args=[followup.id]),
        })

    recent_department_analyses = []
    for analysis in analyses[:6]:
        department = analysis.department
        recent_department_analyses.append({
            'id': analysis.id,
            'departmentId': department.id,
            'department': department.name,
            'company': department.company.name if department.company else '',
            'summary': _ai_workspace_analysis_summary(analysis),
            'meetingCount': analysis.meeting_count,
            'quoteCount': analysis.quote_count,
            'deliveryCount': analysis.delivery_count,
            'updatedAt': _datetime_or_none(analysis.updated_at),
            'href': reverse('ai_chat:department_analysis', args=[department.id]),
        })

    recent_followup_analyses = []
    for analysis in followup_analyses:
        followup = analysis.followup
        recent_followup_analyses.append({
            'id': analysis.id,
            'followupId': followup.id,
            'customer': followup.customer_name or followup.manager or '고객명 미정',
            'company': followup.company.name if followup.company else '',
            'department': followup.department.name if followup.department else '',
            'summary': _ai_workspace_analysis_summary(analysis),
            'meetingCount': analysis.meeting_count,
            'updatedAt': _datetime_or_none(analysis.updated_at),
            'href': reverse('ai_chat:followup_analysis', args=[followup.id]),
        })

    recommended_goals = []
    feedback_goals = _ai_workspace_recent_feedback_goals(
        request.user,
        department_id=detail_department.id if detail_department else None,
    )
    latest_analysis = analyses[0] if analyses else None
    selected_analysis = analysis_map.get(selected_department.id) if selected_department else None
    goals_source_analysis = selected_analysis if selected_department else latest_analysis
    if goals_source_analysis:
        analysis_goals = suggest_goals_from_department_analysis(
            goals_source_analysis,
            customer_names=customer_names_by_department.get(goals_source_analysis.department_id, []),
        )[:6]
        recommended_goals = _ai_workspace_merge_recommended_goals(feedback_goals, analysis_goals, limit=6)
    else:
        recommended_goals = feedback_goals[:6]

    featured_department = None
    if selected_department:
        featured_department = _ai_workspace_featured_department_payload(
            selected_department,
            selected_analysis,
            customer_names_by_department,
            followup_counts_by_department,
            painpoint_counts,
            unverified_counts,
        )
    elif latest_analysis:
        featured_department = _ai_workspace_featured_department_payload(
            latest_analysis.department,
            latest_analysis,
            customer_names_by_department,
            followup_counts_by_department,
            painpoint_counts,
            unverified_counts,
        )
    elif departments:
        featured_department = _ai_workspace_featured_department_payload(
            departments[0],
            None,
            customer_names_by_department,
            followup_counts_by_department,
            painpoint_counts,
            unverified_counts,
        )

    effective_question_department = None
    if featured_department:
        featured_department_id = featured_department.get('departmentId')
        effective_question_department = next(
            (department for department in departments if department.id == featured_department_id),
            None,
        )
    question_history = _ai_workspace_question_history_payload(
        request.user,
        effective_question_department if question_scope == 'department' else None,
        page=question_page,
        scope_type=question_scope,
    )

    prompt_targets = []
    for card in painpoint_cards[:3]:
        department = card.analysis.department
        context, prompt = _ai_workspace_painpoint_prompt(
            card,
            request.user,
            followup_ids_by_department.get(department.id, []),
        )
        prompt_targets.append({
            'id': f'painpoint-{card.id}',
            'type': 'painpoint',
            'typeLabel': 'PainPoint 검증',
            'title': card.hypothesis[:80],
            'subtitle': ' · '.join(_ai_prompt_context(
                department.company.name if department.company else '',
                department.name,
                card.get_category_display(),
            )),
            'priority': f'{card.get_confidence_display()} {card.confidence_score}',
            'context': context[:6],
            'prompt': prompt,
            'href': reverse('ai_chat:department_analysis', args=[department.id]),
        })
    prompt_followups_qs = FollowUp.objects.filter(
        user=request.user,
    )
    if detail_department:
        prompt_followups_qs = prompt_followups_qs.filter(department=detail_department)
    for followup in list(prompt_followups_qs.select_related('company', 'department').order_by('-ai_score', '-updated_at')[:3]):
        analysis = followup_analysis_map.get(followup.id)
        context, prompt = _ai_workspace_followup_prompt(followup, analysis, request.user)
        prompt_targets.append({
            'id': f'followup-{followup.id}',
            'type': 'followup',
            'typeLabel': '고객 후속',
            'title': followup.customer_name or followup.manager or '고객명 미정',
            'subtitle': ' · '.join(_ai_prompt_context(
                followup.company.name if followup.company else '',
                followup.department.name if followup.department else '',
                followup.get_priority_display(),
            )),
            'priority': f'점수 {float(followup.get_combined_score()):.0f}',
            'context': context[:6],
            'prompt': prompt,
            'href': reverse('ai_chat:followup_analysis', args=[followup.id]),
        })
    prompt_departments = [detail_department] if detail_department else departments[:3]
    for department in prompt_departments:
        if department is None:
            continue
        analysis = analysis_map.get(department.id)
        customer_names = customer_names_by_department.get(department.id, [])
        context, prompt = _ai_workspace_department_prompt(
            department,
            analysis,
            customer_names,
            painpoint_counts.get(analysis.id, 0) if analysis else 0,
            unverified_counts.get(analysis.id, 0) if analysis else 0,
            request.user,
            followup_ids_by_department.get(department.id, []),
        )
        prompt_targets.append({
            'id': f'department-{department.id}',
            'type': 'department',
            'typeLabel': '부서 전략',
            'title': ' · '.join(_ai_prompt_context(
                department.company.name if department.company else '',
                department.name,
            )),
            'subtitle': f"고객 {followup_counts_by_department.get(department.id, 0)}명",
            'priority': '분석 완료' if analysis else '분석 필요',
            'context': context[:6],
            'prompt': prompt,
            'href': reverse('ai_chat:department_analysis', args=[department.id]),
        })
    prompt_targets = prompt_targets[:8]

    month_start = today.replace(day=1)
    action_queue = _ai_workspace_build_action_queue(
        request.user,
        week_start,
        week_end,
        department_id=detail_department.id if detail_department else None,
    )
    daily_brief = _ai_workspace_daily_brief(action_queue, week_start, week_end)
    feedback_history = _ai_workspace_feedback_history_payload(request, user_profile, detail_department)

    return JsonResponse({
        'success': True,
        'source': 'django',
        'generatedAt': timezone.now().isoformat(),
        'currentUser': current_user,
        'permission': {
            'canUseAi': True,
            'message': '',
        },
        'metrics': {
            'departmentsWithCustomers': len(department_payload),
            'analyzedDepartments': len(analyses),
            'painpointCards': PainPointCard.objects.filter(analysis__user=request.user).count(),
            'unverifiedPainpoints': PainPointCard.objects.filter(
                analysis__user=request.user,
                verification_status='unverified',
            ).count(),
            'followupAnalyses': AIFollowUpAnalysis.objects.filter(user=request.user).count(),
            'weeklyReportsThisMonth': WeeklyReport.objects.filter(
                user=request.user,
                week_start__gte=month_start,
            ).count(),
        },
        'links': base_links,
        'week': {
            'start': week_start.isoformat(),
            'end': week_end.isoformat(),
        },
        'dailyBrief': daily_brief,
        'actionQueue': action_queue,
        'feedbackHistory': feedback_history,
        'departments': department_payload,
        'recentDepartmentAnalyses': recent_department_analyses,
        'painpoints': painpoint_payload,
        'followupTargets': followup_targets,
        'recentFollowupAnalyses': recent_followup_analyses,
        'promptTargets': prompt_targets,
        'featuredDepartment': featured_department,
        'selectedDepartmentId': featured_department['departmentId'] if featured_department else None,
        'questionHistory': question_history,
        'questionModelChoices': _ai_workspace_question_model_choices_payload(),
        'defaultQuestionModel': AI_WORKSPACE_DEFAULT_QUESTION_MODEL,
        'recommendedGoals': [
            {
                'title': goal.get('title', ''),
                'description': goal.get('description', ''),
                'reason': goal.get('reason', ''),
                'customer': goal.get('customer', ''),
                'priority': goal.get('priority', ''),
                'priorityLabel': goal.get('priorityLabel', ''),
                'source': goal.get('source', ''),
                'sourceLabel': goal.get('sourceLabel', ''),
                'updatedAt': goal.get('updatedAt'),
            }
            for goal in recommended_goals
        ],
    })


@never_cache
@require_http_methods(["GET"])
def ai_workspace_question_log_detail_api(request, question_log_id):
    """Return one AI Workspace question/answer history item for the current user."""
    auth_response = _api_login_required_response(request)
    if auth_response:
        return auth_response

    user_profile = get_user_profile(request.user)
    if not (user_profile and user_profile.can_use_ai):
        return JsonResponse({
            'success': False,
            'error': 'permission_denied',
            'message': 'AI 기능 사용 권한이 없습니다.',
        }, status=403)

    question_log = AIWorkspaceQuestionLog.objects.filter(
        id=question_log_id,
        user=request.user,
    ).select_related(
        'department',
        'department__company',
    ).first()
    if not question_log:
        return JsonResponse({
            'success': False,
            'error': 'question_log_not_found',
            'message': '질문/답변 기록을 찾을 수 없습니다.',
        }, status=404)

    return JsonResponse({
        'success': True,
        'source': 'django',
        'generatedAt': timezone.now().isoformat(),
        'questionLog': _ai_workspace_question_log_payload(question_log),
        'links': {
            'aiWorkspace': _ai_workspace_question_log_detail_link(question_log),
        },
    })


